mapper.select:
select wallet_id, user_id, balance_power, freeze_power, total_recharge_power, total_consume_power, total_give_power, update_time
from ai_c_wallet
where user_id = #{userId}

mapper.update:
update ai_c_wallet
set balance_power = balance_power - #{powerNum},
    total_consume_power = total_consume_power + #{powerNum},
    update_time = sysdate()
where user_id = #{userId}
  and balance_power >= #{powerNum}
